     1→package com.programmersdiary.aidaemon.skills;
     2→
     3→import com.fasterxml.jackson.core.type.TypeReference;
     4→import com.fasterxml.jackson.databind.ObjectMapper;
     5→import com.fasterxml.jackson.databind.SerializationFeature;
     6→import jakarta.annotation.PostConstruct;
     7→import org.springframework.beans.factory.annotation.Value;
     8→import org.springframework.stereotype.Service;
     9→
    10→import java.io.IOException;
    11→import java.io.UncheckedIOException;
    12→import java.nio.file.Files;
    13→import java.nio.file.Path;
    14→import java.util.ArrayList;
    15→import java.util.LinkedHashMap;
    16→import java.util.List;
    17→import java.util.Map;
    18→
    19→@Service
    20→public class SkillsService {
    21→
    22→    private final ObjectMapper objectMapper = new ObjectMapper()
    23→            .enable(SerializationFeature.INDENT_OUTPUT);
    24→    private final Path configDir;
    25→    private final Path skillsDir;
    26→    private final Path memoryFile;
    27→
    28→    public SkillsService(
    29→            @Value("${aidaemon.config-dir:${user.home}/.aidaemon}") String configDir) {
    30→        this.configDir = Path.of(configDir);
    31→        this.skillsDir = this.configDir.resolve("skills");
    32→        this.memoryFile = this.configDir.resolve("memory.json");
    33→    }
    34→
    35→    @PostConstruct
    36→    void init() throws IOException {
    37→        Files.createDirectories(skillsDir);
    38→        if (!Files.exists(memoryFile)) {
    39→            objectMapper.writeValue(memoryFile.toFile(), new LinkedHashMap<>());
    40→        }
    41→    }
    42→
    43→    public Map<String, String> readMemory() {
    44→        try {
    45→            return objectMapper.readValue(memoryFile.toFile(),
    46→                    new TypeReference<LinkedHashMap<String, String>>() {});
    47→        } catch (IOException e) {
    48→            throw new UncheckedIOException(e);
    49→        }
    50→    }
    51→
    52→    public void saveMemory(String key, String value) {
    53→        var memory = readMemory();
    54→        memory.put(key, value);
    55→        try {
    56→            objectMapper.writeValue(memoryFile.toFile(), memory);
    57→        } catch (IOException e) {
    58→            throw new UncheckedIOException(e);
    59→        }
    60→    }
    61→
    62→    public String readFile(String relativePath) {
    63→        var path = skillsDir.resolve(relativePath).normalize();
    64→        if (!path.startsWith(skillsDir)) {
    65→            return "Error: Cannot read files outside the skills folder.";
    66→        }
    67→        try {
    68→            return Files.readString(path);
    69→        } catch (IOException e) {
    70→            return "Error: File not found: " + relativePath;
    71→        }
    72→    }
    73→
    74→    public List<String> listSkills() {
    75→        try (var stream = Files.list(skillsDir)) {
    76→            return stream
    77→                    .filter(Files::isDirectory)
    78→                    .map(p -> p.getFileName().toString())
    79→                    .sorted()
    80→                    .toList();
    81→        } catch (IOException e) {
    82→            return List.of();
    83→        }
    84→    }
    85→
    86→    public List<String> listSkillFiles(String skillName) {
    87→        var skillDir = skillsDir.resolve(skillName).normalize();
    88→        if (!skillDir.startsWith(skillsDir) || !Files.isDirectory(skillDir)) {
    89→            return List.of();
    90→        }
    91→        try (var stream = Files.walk(skillDir)) {
    92→            return stream
    93→                    .filter(Files::isRegularFile)
    94→                    .map(p -> skillsDir.relativize(p).toString().replace('\\', '/'))
    95→                    .sorted()
    96→                    .toList();
    97→        } catch (IOException e) {
    98→            return List.of();
    99→        }
   100→    }
   101→
   102→    public List<String> listAllFiles() {
   103→        var result = new ArrayList<String>();
   104→        for (var skill : listSkills()) {
   105→            result.addAll(listSkillFiles(skill));
   106→        }
   107→        return result;
   108→    }
   109→
   110→    public String installSkill(String slug, Map<String, String> files) {
   111→        var skillDir = skillsDir.resolve(slug);
   112→        try {
   113→            Files.createDirectories(skillDir);
   114→            for (var entry : files.entrySet()) {
   115→                var filePath = skillDir.resolve(entry.getKey()).normalize();
   116→                if (!filePath.startsWith(skillDir)) continue;
   117→                Files.createDirectories(filePath.getParent());
   118→                Files.writeString(filePath, entry.getValue());
   119→            }
   120→            return slug;
   121→        } catch (IOException e) {
   122→            throw new UncheckedIOException(e);
   123→        }
   124→    }
   125→
   126→    public boolean removeSkill(String skillName) {
   127→        var skillDir = skillsDir.resolve(skillName).normalize();
   128→        if (!skillDir.startsWith(skillsDir) || !Files.isDirectory(skillDir)) {
   129→            return false;
   130→        }
   131→        try (var stream = Files.walk(skillDir)) {
   132→            stream.sorted(java.util.Comparator.reverseOrder())
   133→                    .forEach(p -> {
   134→                        try { Files.delete(p); } catch (IOException ignored) {}
   135→                    });
   136→            return true;
   137→        } catch (IOException e) {
   138→            return false;
   139→        }
   140→    }
   141→}
