     1→package com.programmersdiary.aidaemon.skills;
     2→
     3→import org.springframework.ai.tool.annotation.Tool;
     4→import org.springframework.ai.tool.annotation.ToolParam;
     5→
     6→import java.io.IOException;
     7→import java.util.concurrent.TimeUnit;
     8→
     9→public class ShellTool {
    10→
    11→    private static final long TIMEOUT_SECONDS = 60;
    12→
    13→    private final ShellAccessService shellAccessService;
    14→
    15→    public ShellTool(ShellAccessService shellAccessService) {
    16→        this.shellAccessService = shellAccessService;
    17→    }
    18→
    19→    @Tool(description = "Execute a shell command on the host system and return its output. Use this to run CLI tools like git, gh, docker, curl, etc.")
    20→    public String executeCommand(
    21→            @ToolParam(description = "The command to execute") String command) {
    22→        if (!shellAccessService.isEnabled()) {
    23→            return "Error: Shell access is currently disabled.";
    24→        }
    25→        try {
    26→            var isWindows = System.getProperty("os.name").toLowerCase().contains("win");
    27→            var processBuilder = isWindows
    28→                    ? new ProcessBuilder("cmd", "/c", command)
    29→                    : new ProcessBuilder("sh", "-c", command);
    30→            processBuilder.redirectErrorStream(true);
    31→
    32→            var process = processBuilder.start();
    33→            var output = new String(process.getInputStream().readAllBytes());
    34→            var finished = process.waitFor(TIMEOUT_SECONDS, TimeUnit.SECONDS);
    35→
    36→            if (!finished) {
    37→                process.destroyForcibly();
    38→                return "Command timed out after " + TIMEOUT_SECONDS + " seconds.\nPartial output:\n" + output;
    39→            }
    40→
    41→            var exitCode = process.exitValue();
    42→            if (exitCode != 0) {
    43→                return "Exit code: " + exitCode + "\n" + output;
    44→            }
    45→            return output.isBlank() ? "(no output)" : output;
    46→        } catch (IOException | InterruptedException e) {
    47→            return "Error executing command: " + e.getMessage();
    48→        }
    49→    }
    50→}
