     1→package com.programmersdiary.aidaemon.chat;
     2→
     3→import org.springframework.stereotype.Service;
     4→
     5→import java.util.concurrent.CompletableFuture;
     6→import java.util.concurrent.ConcurrentHashMap;
     7→
     8→@Service
     9→public class ToolApprovalService {
    10→
    11→    private final ConcurrentHashMap<String, CompletableFuture<Boolean>> pending = new ConcurrentHashMap<>();
    12→
    13→    public CompletableFuture<Boolean> requestApproval(String approvalId) {
    14→        var future = new CompletableFuture<Boolean>();
    15→        pending.put(approvalId, future);
    16→        return future;
    17→    }
    18→
    19→    public void approve(String approvalId) {
    20→        var future = pending.remove(approvalId);
    21→        if (future != null) {
    22→            future.complete(true);
    23→        }
    24→    }
    25→
    26→    public void reject(String approvalId) {
    27→        var future = pending.remove(approvalId);
    28→        if (future != null) {
    29→            future.complete(false);
    30→        }
    31→    }
    32→
    33→    public boolean hasPending() {
    34→        return !pending.isEmpty();
    35→    }
    36→}
