    68→    public List<ToolCallback> buildToolCallbacks(StreamRequestMetadata meta, String providerId) {
    69→        var filtered = meta.messages().stream().filter(m -> !"tool".equals(m.role())).toList();
    70→        var list = new ArrayList<ToolCallback>();
    71→
    72→        list.addAll(Arrays.asList(ToolCallbacks.from(new ChatTools(skillsService, jobExecutor, providerId, filtered,
    73→                meta.conversationLimit(), meta.botName(), botRepository))));
    74→        list.addAll(Arrays.asList(ToolCallbacks.from(new ShellTool(shellAccessService))));
    75→
    76→        var botName = meta.botName();
    77→        if (botName != null && !botName.isBlank() && !"default".equalsIgnoreCase(botName)) {
    78→            list.addAll(Arrays.asList(ToolCallbacks.from(new BotToBotTool(conversationService, botRepository, providerId, botName))));
    79→        }
    80→        if (smitheryMcpTool != null) {
    81→            list.addAll(Arrays.asList(ToolCallbacks.from(smitheryMcpTool)));
    82→        }
    83→        if (smitherySkillTool != null) {
    84→            list.addAll(Arrays.asList(ToolCallbacks.from(smitherySkillTool)));
    85→        }
    86→        mcpService.getToolCallbacksByServer().forEach((serverName, callbacks) -> list.addAll(callbacks));
    87→
    88→        providerConfigRepository.findAll().stream()
    89→                .filter(c -> c.type() == ProviderType.DALLE_3)
    90→                .findFirst()
    91→                .ifPresent(dalleConfig -> {
    92→                    var factory = new SimpleClientHttpRequestFactory();
    93→                    factory.setConnectTimeout(Duration.ofSeconds(30));
    94→                    factory.setReadTimeout(Duration.ofSeconds(120));
    95→                    var imageApi = OpenAiImageApi.builder()
    96→                            .apiKey(dalleConfig.apiKey())
    97→                            .restClientBuilder(RestClient.builder().requestFactory(factory))
    98→                            .build();
    99→                    var imageModel = new OpenAiImageModel(imageApi);
   100→                    list.addAll(Arrays.asList(ToolCallbacks.from(
   101→                            new ImageGenerationTool(fileStorageService, imageModel, meta.conversationId()))));
   102→                });
   103→
   104→        return list;
   105→    }
   106→}
