   634→    }
   635→    const SpeechRecognitionAPI =
   636→      (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
   637→    if (!SpeechRecognitionAPI) {
   638→      alert('Speech recognition is not supported in this browser. Try Chrome or Edge.');
   639→      return;
   640→    }
   641→    const recognition = new SpeechRecognitionAPI();
   642→    recognition.continuous = true;
   643→    recognition.interimResults = true;
   644→    recognition.lang = 'en-US';
   645→    // Capture the base text at recording start; all mutations use this as ground truth
   646→    const startBase = editableRef.current ? editablePlainText(editableRef.current) : inputDraft;
   647→    let committedText = startBase;
