     1→package com.programmersdiary.aidaemon.files;
     2→
     3→import com.fasterxml.jackson.databind.ObjectMapper;
     4→import org.springframework.beans.factory.annotation.Value;
     5→import org.springframework.stereotype.Service;
     6→
     7→import java.io.IOException;
     8→import java.nio.file.Files;
     9→import java.nio.file.Path;
    10→import java.util.UUID;
    11→
    12→@Service
    13→public class FileStorageService {
    14→
    15→    private static final ObjectMapper OBJECT_MAPPER = new ObjectMapper();
    16→
    17→    private final Path conversationsDir;
    18→
    19→    public FileStorageService(
    20→            @Value("${aidaemon.config-dir:#{systemProperties['user.home'] + '/.aidaemon'}}") String configDir) {
    21→        this.conversationsDir = Path.of(configDir).resolve("conversations");
    22→    }
    23→
    24→    public FileAttachment store(String conversationId, String originalName, String mimeType, byte[] data) throws IOException {
    25→        var id = UUID.randomUUID().toString();
    26→        var filesDir = filesDir(conversationId);
    27→        Files.createDirectories(filesDir);
    28→        Files.write(binaryPath(filesDir, id, originalName), data);
    29→        var attachment = new FileAttachment(id, originalName, mimeType);
    30→        OBJECT_MAPPER.writeValue(filesDir.resolve(id + ".meta").toFile(), attachment);
    31→        return attachment;
    32→    }
    33→
    34→    public byte[] getBytes(String id) throws IOException {
    35→        var attachment = getAttachment(id);
    36→        var filesDir = findFilesDir(id);
    37→        var path = binaryPath(filesDir, id, attachment.name());
    38→        if (!Files.exists(path)) {
    39→            throw new IOException("File not found: " + id);
    40→        }
    41→        return Files.readAllBytes(path);
    42→    }
    43→
    44→    public FileAttachment getAttachment(String id) throws IOException {
    45→        var filesDir = findFilesDir(id);
    46→        return OBJECT_MAPPER.readValue(filesDir.resolve(id + ".meta").toFile(), FileAttachment.class);
    47→    }
    48→
    49→    private Path findFilesDir(String id) throws IOException {
    50→        if (Files.exists(conversationsDir)) {
    51→            try (var stream = Files.list(conversationsDir)) {
    52→                var found = stream
    53→                        .filter(Files::isDirectory)
    54→                        .map(dir -> dir.resolve("files"))
    55→                        .filter(filesDir -> Files.exists(filesDir.resolve(id + ".meta")))
    56→                        .findFirst();
    57→                if (found.isPresent()) return found.get();
    58→            }
    59→        }
    60→        throw new IOException("File metadata not found: " + id);
    61→    }
    62→
    63→    private Path filesDir(String conversationId) {
    64→        return conversationsDir.resolve(conversationId).resolve("files");
    65→    }
    66→
    67→    private Path binaryPath(Path filesDir, String id, String originalName) {
    68→        var ext = fileExtension(originalName);
    69→        return filesDir.resolve(ext.isEmpty() ? id : id + "." + ext);
    70→    }
    71→
    72→    private static String fileExtension(String filename) {
    73→        if (filename == null) return "";
    74→        int dot = filename.lastIndexOf('.');
    75→        return (dot >= 0 && dot < filename.length() - 1) ? filename.substring(dot + 1) : "";
    76→    }
    77→}
    78→

