    81→        var p1 = userParticipantId.compareTo(botName) <= 0 ? userParticipantId : botName;
    82→        var p2 = userParticipantId.compareTo(botName) <= 0 ? botName : userParticipantId;
    83→        return conversationRepository.findById(id)
    84→                .map(conv -> {
    85→                    if (providerId != null && !providerId.isBlank() && !providerId.equals(conv.providerId())) {
