    28→function formatTime(ms: number): string {
    29→  const d = new Date(ms);
    30→  const pad = (n: number) => n.toString().padStart(2, '0');
    31→  const pad3 = (n: number) => n.toString().padStart(3, '0');
    32→  return `${pad(d.getHours())}:${pad(d.getMinutes())}:${pad(d.getSeconds())}.${pad3(d.getMilliseconds())}`;
    33→}
    34→
    35→function roleDisplayName(role: string, conversation: Conversation | null): string {
    36→  if (!conversation) return role;
    37→  if (role === 'user') {
    38→    const p1 = conversation.participant1 ?? '';
    39→    const p2 = conversation.participant2 ?? '';
    40→    const bot = conversation.botName ?? '';
    41→    if (p1 && p2 && bot && p1 !== 'user' && p2 !== 'user') {
    42→      return p1 === bot ? p2 : p1;
    43→    }
    44→    return 'user';
    45→  }
    46→  if (role === 'assistant') {
    47→    const bot = conversation.botName ?? '';
    48→    if (bot) return bot;
    49→    const p1 = conversation.participant1 ?? '';
    50→    const p2 = conversation.participant2 ?? '';
    51→    if (p1 && p2) return p1 === 'user' ? p2 : p2 === 'user' ? p1 : p2;
    52→  }
    53→  return role;
    54→}
    55→
    56→function getMessagePlainText(msg: DisplayMessage, includeThinking: boolean): string {
    57→  if ('parts' in msg && msg.parts != null) {
    58→    return msg.parts
    59→      .filter((p) => p.type === 'answer' || (includeThinking && p.type === 'reasoning'))
    60→      .map((p) => p.content)
    61→      .join(' ')
    62→      .trim();
    63→  }
    64→  if ('content' in msg) return msg.content;
    65→  return '';
    66→}
