   135→function ToolApprovalCard({
   136→  approval,
   137→  onApprove,
   138→  onReject,
   139→}: {
   140→  approval: PendingToolApproval;
   141→  onApprove: () => void;
   142→  onReject: () => void;
   143→}) {
   144→  const [expanded, setExpanded] = useState(true);
