   302→
   303→function renderAnswerContent(content: string): ReactNode {
   304→  const imgRegex = /!\[([^\]]*)\]\((\/api\/files\/[^)]+)\)/g;
   305→  const nodes: React.ReactNode[] = [];
   306→  let lastIndex = 0;
   307→  let match: RegExpExecArray | null;
   308→  while ((match = imgRegex.exec(content)) !== null) {
   309→    if (match.index > lastIndex) {
   310→      nodes.push(<span key={lastIndex}>{content.slice(lastIndex, match.index)}</span>);
   311→    }
   312→    nodes.push(
   313→      <img
   314→        key={match.index}
   315→        src={match[2]}
   316→        alt={match[1]}
   317→        className="max-w-full rounded-lg my-2 block"
   318→        style={{ maxHeight: '512px' }}
   319→      />
   320→    );
   321→    lastIndex = imgRegex.lastIndex;
   322→  }
   323→  if (lastIndex < content.length) {
   324→    nodes.push(<span key={lastIndex}>{content.slice(lastIndex)}</span>);
   325→  }
   326→  return nodes.length > 0 ? <>{nodes}</> : content;
   327→}
   328→
   329→function parseStructuredContent(content: string): StreamPart[] | null {
   330→  if (!content || typeof content !== 'string') return null;
   331→  const trimmed = content.trim();
   332→  if (!trimmed.startsWith('{"parts":')) return null;
   333→  try {
   334→    const data = JSON.parse(content) as { parts?: Array<{ type: string; content: string }> };
   335→    if (!Array.isArray(data.parts)) return null;
   336→    const parts: StreamPart[] = data.parts
   337→      .filter((p) => p && (p.type === 'answer' || p.type === 'tool' || p.type === 'reasoning') && typeof p.content === 'string')
   338→      .map((p) => ({ type: p.type as 'answer' | 'tool' | 'reasoning', content: p.content }));
   339→    return parts.length > 0 ? parts : null;
   340→  } catch {
   341→    return null;
   342→  }
   343→}
   344→
   345→function filterParts(parts: StreamPart[], hideToolsAndThinking: boolean): StreamPart[] {
   346→  if (!hideToolsAndThinking) return parts;
   347→  const answerParts = parts.filter((p) => p.type === 'answer');
   348→  return answerParts.map((p, i, arr) => ({
   349→    ...p,
   350→    content: p.content + (i < arr.length - 1 ? '\n\n' : ''),
   351→  }));
   352→}
   353→
   354→function getDisplayMessages(
   355→  messages: ChatMessage[],
   356→  hideToolsAndThinking: boolean,
   357→  lastStreamedContent: { reasoning: string; parts: StreamPart[] } | null
   358→): DisplayMessage[] {
   359→  let list: DisplayMessage[] = messages.map((msg) => {
   360→    if (msg.role === 'assistant') {
   361→      const parts = parseStructuredContent(msg.content);
   362→      if (parts) return { role: 'assistant' as const, parts: filterParts(parts, hideToolsAndThinking) };
   363→    }
   364→    return msg;
   365→  });
   366→  if (lastStreamedContent && list.length > 0) {
   367→    const lastUserIdx = Math.max(...list.map((msg, i) => (msg.role === 'user' ? i : -1)));
   368→    const afterLastUser = list.slice(lastUserIdx + 1);
   369→    if (afterLastUser.length === 1 && afterLastUser[0].role === 'assistant') {
   370→      const parts: StreamPart[] = lastStreamedContent.reasoning
   371→        ? [{ type: 'reasoning', content: lastStreamedContent.reasoning }, ...lastStreamedContent.parts]
   372→        : lastStreamedContent.parts;
   373→      list = [...list.slice(0, lastUserIdx + 1), { role: 'assistant', parts: filterParts(parts, hideToolsAndThinking) }];
   374→    }
   375→  }
   376→  return list;
   377→}
   378→
   379→// CSS class applied to inline file chips inside the contentEditable input div.
   380→// Must match classes used in JSX FileChip to survive Tailwind tree-shaking.
   381→const FILE_CHIP_CLASS =
   382→  'inline-flex items-center gap-1 py-0.5 pl-1.5 pr-1 rounded border border-border bg-bg-input text-text-dim text-xs mx-0.5 align-middle select-none';
   383→
   384→function editablePlainText(el: HTMLDivElement): string {
   385→  let text = '';
   386→  el.childNodes.forEach((n) => {
   387→    if (n.nodeType === Node.TEXT_NODE) text += n.textContent ?? '';
   388→  });
   389→  return text;
   390→}
   391→
   392→function editableHasContent(el: HTMLDivElement): boolean {
   393→  if (editablePlainText(el).trim()) return true;
   394→  return Array.from(el.childNodes).some(
   395→    (n) => n.nodeType === Node.ELEMENT_NODE && !!(n as HTMLElement).dataset.fileId
   396→  );
   397→}
   398→
   399→type UserPart = { type: 'text'; content: string } | { type: 'file'; id: string; name: string; mimeType: string };
   400→
   401→function parseUserParts(content: string): UserPart[] | null {
   402→  if (!content || !content.trim().startsWith('{"user_parts":')) return null;
   403→  try {
   404→    const data = JSON.parse(content) as { user_parts?: Array<{ type: string; content?: string; id?: string; name?: string; mimeType?: string }> };
   405→    if (!Array.isArray(data.user_parts)) return null;
   406→    return data.user_parts
   407→      .filter((p) => p.type === 'text' || p.type === 'file')
   408→      .map((p) =>
   409→        p.type === 'file'
   410→          ? { type: 'file' as const, id: p.id ?? '', name: p.name ?? '', mimeType: p.mimeType ?? '' }
   411→          : { type: 'text' as const, content: p.content ?? '' }
   412→      );
   413→  } catch {
   414→    return null;
   415→  }
   416→}
   417→
   418→function extractEditableContent(el?: HTMLDivElement | null): { parts: UserPart[]; files: FileAttachment[] } {
   419→  if (!el) return { parts: [], files: [] };
   420→  const rawParts: UserPart[] = [];
   421→  const files: FileAttachment[] = [];
   422→  el.childNodes.forEach((n) => {
   423→    if (n.nodeType === Node.TEXT_NODE) {
   424→      const text = n.textContent ?? '';
   425→      if (text) {
   426→        const last = rawParts[rawParts.length - 1];
   427→        if (last?.type === 'text') {
   428→          (last as { type: 'text'; content: string }).content += text;
   429→        } else {
   430→          rawParts.push({ type: 'text', content: text });
   431→        }
   432→      }
   433→    } else if (n.nodeType === Node.ELEMENT_NODE) {
   434→      const span = n as HTMLElement;
   435→      if (span.dataset.fileId) {
   436→        const file: FileAttachment = { id: span.dataset.fileId, name: span.dataset.fileName ?? '', mimeType: span.dataset.fileMimeType ?? '' };
   437→        rawParts.push({ type: 'file', id: file.id, name: file.name, mimeType: file.mimeType });
   438→        files.push(file);
   439→      }
   440→    }
   441→  });
   442→  // Trim leading/trailing whitespace from boundary text parts
   443→  if (rawParts.length > 0 && rawParts[0].type === 'text') {
   444→    (rawParts[0] as { type: 'text'; content: string }).content = (rawParts[0] as { type: 'text'; content: string }).content.trimStart();
   445→  }
   446→  const lastPart = rawParts[rawParts.length - 1];
   447→  if (lastPart?.type === 'text') {
   448→    (lastPart as { type: 'text'; content: string }).content = (lastPart as { type: 'text'; content: string }).content.trimEnd();
   449→  }
   450→  const parts = rawParts.filter((p) => p.type === 'file' || (p as { type: 'text'; content: string }).content.length > 0);
   451→  return { parts, files };
   452→}
   453→
   454→function escapeHtml(s: string): string {
   455→  return s.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
   456→}
   457→
   458→export default function ChatWindow({
   459→  headerTitle,
   460→  conversation,
   461→  providers,
   462→  bots,
   463→  sending,
   464→  streaming,
   465→  lastStreamedContent,
   466→  inputDraft,
   467→  onInputDraftChange,
   468→  onSend,
   469→  onUpdateProvider,
   470→  onUpdateBot,
   471→  pendingApprovals,
   472→  onApproveTool,
   473→  onRejectTool,
   474→}: ChatWindowProps) {
   475→  const [hideToolsAndThinking, setHideToolsAndThinking] = useState(false);
   476→  const [isRecording, setIsRecording] = useState(false);
   477→  const [speakingIdx, setSpeakingIdx] = useState<number | null>(null);
   478→  const [uploadingFile, setUploadingFile] = useState(false);
   479→  const [hasContent, setHasContent] = useState(false);
   480→  const messagesRef = useRef<HTMLDivElement>(null);
   481→  const topRef = useRef<HTMLDivElement>(null);
   482→  const bottomRef = useRef<HTMLDivElement>(null);
   483→  const recognitionRef = useRef<any>(null);
   484→  const fileInputRef = useRef<HTMLInputElement>(null);
   485→  const editableRef = useRef<HTMLDivElement>(null);
   486→  // true while we are the source of an inputDraft change — prevents syncing back
   487→  const isInternalChangeRef = useRef(false);
   488→
   489→  // Stop recording and TTS when conversation changes
   490→  useEffect(() => {
   491→    recognitionRef.current?.stop();
   492→    setIsRecording(false);
   493→    speechSynthesis.cancel();
   494→    setSpeakingIdx(null);
   495→  }, [conversation?.id]);
   496→
   497→  // Sync external inputDraft changes (e.g. speech recognition) into the editable div
   498→  // while preserving file chips already embedded in the div.
   499→  useLayoutEffect(() => {
   500→    if (isInternalChangeRef.current) {
   501→      isInternalChangeRef.current = false;
   502→      return;
   503→    }
   504→    const el = editableRef.current;
   505→    if (!el) return;
   506→    // Collect existing chip nodes to re-append after text
   507→    const chips = Array.from(el.childNodes).filter(
   508→      (n) => n.nodeType === Node.ELEMENT_NODE && (n as HTMLElement).dataset.fileId
   509→    );
   510→    el.innerHTML = '';
   511→    if (inputDraft) el.appendChild(document.createTextNode(inputDraft));
   512→    chips.forEach((c) => el.appendChild(c));
   513→    setHasContent(editableHasContent(el));
   514→  }, [inputDraft]);
   515→
   516→  const visibleMessages = conversation
   517→    ? getDisplayMessages(conversation.messages, hideToolsAndThinking, lastStreamedContent)
   518→    : [];
   519→
   520→  useEffect(() => {
   521→    bottomRef.current?.scrollIntoView({ behavior: 'smooth' });
   522→  }, [conversation?.messages.length, streaming?.reasoning, streaming?.parts?.length]);
   523→
   524→  const hasProvider = Boolean(conversation?.providerId);
   525→  const isDirectChat = Boolean(
   526→    conversation?.participant1 != null && conversation?.participant2 != null
   527→  );
   528→
   529→  const handleSend = () => {
   530→    if (sending || !hasProvider) return;
   531→    const { parts, files } = extractEditableContent(editableRef.current);
   532→    if (parts.length === 0) return;
   533→    const el = editableRef.current;
   534→    if (el) {
   535→      el.innerHTML = '';
   536→      isInternalChangeRef.current = true;
   537→      onInputDraftChange('');
   538→      setHasContent(false);
   539→    }
   540→    const message = files.length > 0
   541→      ? JSON.stringify({ user_parts: parts })
   542→      : ((parts[0] as { type: 'text'; content: string })?.content ?? '');
   543→    onSend(message, files.length > 0 ? files : undefined);
   544→  };
   545→
   546→  const handleEditableInput = () => {
   547→    const el = editableRef.current;
   548→    if (!el) return;
   549→    isInternalChangeRef.current = true;
   550→    onInputDraftChange(editablePlainText(el));
   551→    setHasContent(editableHasContent(el));
   552→  };
   553→
   554→  const handleEditableClick = (e: React.MouseEvent<HTMLDivElement>) => {
   555→    const target = e.target as HTMLElement;
   556→    if (target.dataset.removeChipId) {
   557→      const chip = target.closest('[data-file-id]') as HTMLElement | null;
   558→      chip?.remove();
   559→      isInternalChangeRef.current = true;
   560→      const el = editableRef.current;
   561→      if (el) {
   562→        onInputDraftChange(editablePlainText(el));
   563→        setHasContent(editableHasContent(el));
   564→      }
   565→    }
   566→  };
   567→
   568→  const handleFileSelect = async (e: React.ChangeEvent<HTMLInputElement>) => {
   569→    const files = Array.from(e.target.files ?? []);
   570→    if (files.length === 0) return;
   571→    e.target.value = '';
   572→    setUploadingFile(true);
   573→    try {
   574→      const uploaded = await Promise.all(files.map((f) => api.uploadFile(conversation!.id, f)));
   575→      uploaded.forEach(insertFileChip);
   576→    } catch {
   577→      // ignore upload errors silently
   578→    } finally {
   579→      setUploadingFile(false);
   580→    }
   581→  };
   582→
   583→  const insertFileChip = (attachment: FileAttachment) => {
   584→    const el = editableRef.current;
   585→    if (!el) return;
   586→    el.focus();
   587→    const chip = document.createElement('span');
   588→    chip.contentEditable = 'false';
   589→    chip.dataset.fileId = attachment.id;
   590→    chip.dataset.fileName = attachment.name;
   591→    chip.dataset.fileMimeType = attachment.mimeType;
   592→    chip.className = FILE_CHIP_CLASS;
   593→    chip.title = attachment.name;
   594→    chip.innerHTML =
   595→      `<svg width="11" height="11" viewBox="0 0 12 12" fill="none" stroke="currentColor" stroke-width="1.2" stroke-linecap="round" stroke-linejoin="round" style="flex-shrink:0"><path d="M7 1H3a1 1 0 00-1 1v8a1 1 0 001 1h6a1 1 0 001-1V4L7 1z"/><path d="M7 1v3h3"/></svg>` +
   596→      `<span style="max-width:120px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${escapeHtml(attachment.name)}</span>` +
   597→      `<span data-remove-chip-id="${attachment.id}" style="cursor:pointer;margin-left:2px;opacity:0.7;flex-shrink:0" title="Remove">✕</span>`;
   598→
   599→    const sel = window.getSelection();
   600→    if (sel && sel.rangeCount > 0 && el.contains(sel.getRangeAt(0).commonAncestorContainer)) {
   601→      const range = sel.getRangeAt(0);
   602→      range.deleteContents();
   603→      range.insertNode(chip);
   604→      range.setStartAfter(chip);
   605→      range.collapse(true);
   606→      sel.removeAllRanges();
   607→      sel.addRange(range);
   608→    } else {
   609→      el.appendChild(chip);
   610→    }
   611→    // Ensure a text node follows so typing continues naturally
   612→    const space = document.createTextNode('\u00A0');
   613→    chip.after(space);
   614→    const r = document.createRange();
   615→    r.setStart(space, 1);
   616→    r.collapse(true);
   617→    const s = window.getSelection();
   618→    s?.removeAllRanges();
   619→    s?.addRange(r);
   620→
   621→    isInternalChangeRef.current = true;
   622→    onInputDraftChange(editablePlainText(el));
   623→    setHasContent(true);
   624→  };
   625→
   626→  const scrollToTop = () => topRef.current?.scrollIntoView({ behavior: 'smooth' });
   627→  const scrollToBottom = () => bottomRef.current?.scrollIntoView({ behavior: 'smooth' });
   628→
   629→  const toggleRecording = () => {
   630→    if (isRecording) {
   631→      recognitionRef.current?.stop();
   632→      setIsRecording(false);
   633→      return;
   634→    }
   635→    const SpeechRecognitionAPI =
   636→      (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
   637→    if (!SpeechRecognitionAPI) {
   638→      alert('Speech recognition is not supported in this browser. Try Chrome or Edge.');
   639→      return;
   640→    }
   641→    const recognition = new SpeechRecognitionAPI();
   642→    recognition.continuous = true;
   643→    recognition.interimResults = true;
   644→    recognition.lang = 'en-US';
   645→    // Capture the base text at recording start; all mutations use this as ground truth
   646→    const startBase = editableRef.current ? editablePlainText(editableRef.current) : inputDraft;
   647→    let committedText = startBase;
   648→    recognition.onresult = (event: any) => {
   649→      let interim = '';
   650→      for (let i = event.resultIndex; i < event.results.length; i++) {
   651→        const t = event.results[i][0].transcript;
   652→        if (event.results[i].isFinal) {
   653→          committedText += (committedText && !committedText.endsWith(' ') ? ' ' : '') + t.trim();
   654→        } else {
   655→          interim = t;
   656→        }
   657→      }
   658→      if (interim) {
   659→        onInputDraftChange(committedText + (committedText && !committedText.endsWith(' ') ? ' ' : '') + interim + ' […]');
   660→      } else {
   661→        onInputDraftChange(committedText);
   662→      }
   663→    };
   664→    recognition.onend = () => {
   665→      setIsRecording(false);
   666→      onInputDraftChange(committedText);
   667→    };
   668→    recognition.onerror = () => {
   669→      setIsRecording(false);
   670→      onInputDraftChange(committedText);
   671→    };
   672→    recognitionRef.current = recognition;
   673→    recognition.start();
   674→    setIsRecording(true);
   675→  };
   676→
   677→  const speakMessage = (msg: DisplayMessage, idx: number) => {
   678→    if (speakingIdx === idx) {
   679→      speechSynthesis.cancel();
   680→      setSpeakingIdx(null);
   681→      return;
   682→    }
   683→    const text = getMessagePlainText(msg, !hideToolsAndThinking);
   684→    if (!text.trim()) return;
   685→    speechSynthesis.cancel();
   686→    const utterance = new SpeechSynthesisUtterance(text);
   687→    utterance.onend = () => setSpeakingIdx(null);
   688→    utterance.onerror = () => setSpeakingIdx(null);
   689→    setSpeakingIdx(idx);
   690→    speechSynthesis.speak(utterance);
   691→  };
   692→
   693→  if (!conversation) {
   694→    return (
   695→      <main className="flex-1 flex flex-col min-w-0">
   696→        <header className="flex flex-wrap items-center gap-3 py-3.5 px-5 border-b border-border">
   697→          <h2 className="flex-1 min-w-0 text-base font-semibold text-text-bright truncate">{headerTitle}</h2>
   698→        </header>
   699→        <div className="flex-1 flex items-center justify-center text-text-dim text-base">
   700→          <p>
   701→            {headerTitle === 'User'
   702→              ? 'Select or create a conversation to start chatting'
   703→              : `Select or create a conversation with ${headerTitle} to start chatting`}
   704→          </p>
   705→        </div>
   706→      </main>
   707→    );
   708→  }
   709→
   710→  return (
   711→    <main className="flex-1 flex flex-col min-w-0">
   712→      <header className="flex flex-wrap items-center gap-3 py-3.5 px-5 border-b border-border">
   713→        <h2 className="flex-1 min-w-0 text-base font-semibold text-text-bright truncate">{headerTitle}</h2>
   714→        <button
   715→          className={`py-1 px-3 border rounded-lg cursor-pointer text-xs transition-all duration-150 whitespace-nowrap ${
