    55→        Executors.newSingleThreadExecutor().submit(() -> {
    56→            // Wait until a pending approval appears
    57→            while (approvalService.hasPending()) {
    58→                // poll
    59→            }
    60→            // Actually wait for the future to be registered
    61→            try { Thread.sleep(50); } catch (InterruptedException e) { Thread.currentThread().interrupt(); }
    62→            // Approve all pending (we'll use the captured ID from the chunk)
    63→            if (capturedId.get() != null) {
    64→                approvalService.approve(capturedId.get());
    65→            }
    66→        });
    67→
    68→        // Capture the approvalId from the pending chunk before calling
    69→        // We run the call in a thread so we can approve concurrently
    70→        var callThread = Executors.newSingleThreadExecutor();
    71→        var futureResult = callThread.submit(() -> {
    72→            // Need to capture approvalId from the first chunk emitted
