package com.programmersdiary.aidaemon.skills;

import com.fasterxml.jackson.databind.ObjectMapper;
import com.programmersdiary.aidaemon.chat.StreamChunk;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;

import java.nio.file.Files;
import java.nio.file.Path;
import java.util.ArrayList;
import java.util.concurrent.Executors;
import java.util.concurrent.TimeUnit;
import java.util.concurrent.atomic.AtomicReference;

import static org.junit.jupiter.api.Assertions.*;

class FileEditToolTest {

    private static final ObjectMapper JSON = new ObjectMapper();

    @TempDir
    Path tempDir;

    private ShellAccessService enabledShellAccess() {
        var s = new ShellAccessService(true);
        return s;
    }

    private ShellAccessService disabledShellAccess() {
        return new ShellAccessService(false);
    }

    @Test
    void createFile_whenShellDisabled_returnsError() {
        var tool = new FileEditTool(disabledShellAccess(), new FileChangeService(), chunk -> {});
        var result = tool.createFile(tempDir.resolve("test.txt").toString(), "content");
        assertTrue(result.toLowerCase().contains("disabled") || result.toLowerCase().contains("error"));
    }

    @Test
    void modifyFile_whenShellDisabled_returnsError() {
        var tool = new FileEditTool(disabledShellAccess(), new FileChangeService(), chunk -> {});
        var result = tool.modifyFile(tempDir.resolve("test.txt").toString(), "content");
        assertTrue(result.toLowerCase().contains("disabled") || result.toLowerCase().contains("error"));
    }

    @Test
    void deleteFile_whenShellDisabled_returnsError() {
        var tool = new FileEditTool(disabledShellAccess(), new FileChangeService(), chunk -> {});
        var result = tool.deleteFile(tempDir.resolve("test.txt").toString());
        assertTrue(result.toLowerCase().contains("disabled") || result.toLowerCase().contains("error"));
    }

    @Test
    void createFile_whenApproved_writesFileAndReturnsSuccess() throws Exception {
        var fileChangeService = new FileChangeService();
        var chunks = new ArrayList<StreamChunk>();
        var tool = new FileEditTool(enabledShellAccess(), fileChangeService, chunks::add);
        var filePath = tempDir.resolve("new.txt").toString();
        var content = "hello world";

        var result = runWithAutoApprove(fileChangeService, chunks, () -> tool.createFile(filePath, content));

        assertFalse(Files.notExists(Path.of(filePath)), "File should exist after creation");
        assertEquals(content, Files.readString(Path.of(filePath)));
        assertTrue(result.toLowerCase().contains("created") || result.toLowerCase().contains("success"));
    }

    @Test
    void createFile_whenRejected_doesNotWriteFile() throws Exception {
        var fileChangeService = new FileChangeService();
        var chunks = new ArrayList<StreamChunk>();
        var tool = new FileEditTool(enabledShellAccess(), fileChangeService, chunks::add);
        var filePath = tempDir.resolve("rejected.txt").toString();

        var result = runWithAutoReject(fileChangeService, chunks, () -> tool.createFile(filePath, "content"));

        assertFalse(Files.exists(Path.of(filePath)), "File should NOT exist after rejection");
        assertTrue(result.toLowerCase().contains("rejected") || result.toLowerCase().contains("cancel"));
    }

    @Test
    void modifyFile_whenApproved_overwritesFile() throws Exception {
        var filePath = tempDir.resolve("existing.txt");
        Files.writeString(filePath, "old content");

        var fileChangeService = new FileChangeService();
        var chunks = new ArrayList<StreamChunk>();
        var tool = new FileEditTool(enabledShellAccess(), fileChangeService, chunks::add);

        runWithAutoApprove(fileChangeService, chunks, () -> tool.modifyFile(filePath.toString(), "new content"));

        assertEquals("new content", Files.readString(filePath));
    }

    @Test
    void modifyFile_whenFileDoesNotExist_treatsOldContentAsEmpty() throws Exception {
        var fileChangeService = new FileChangeService();
        var chunks = new ArrayList<StreamChunk>();
        var tool = new FileEditTool(enabledShellAccess(), fileChangeService, chunks::add);
        var filePath = tempDir.resolve("nonexistent.txt").toString();

        var capturedPendingJson = new AtomicReference<String>();
        var capturingTool = new FileEditTool(enabledShellAccess(), fileChangeService, chunk -> {
            chunks.add(chunk);
            if (StreamChunk.TYPE_FILE_CHANGE_PENDING.equals(chunk.type())) {
                capturedPendingJson.set(chunk.content());
                approveFirstPending(fileChangeService, chunk.content());
            }
        });

        capturingTool.modifyFile(filePath, "new content");

        var pending = JSON.readTree(capturedPendingJson.get());
        assertEquals("", pending.get("oldContent").asText());
        assertEquals("new content", pending.get("newContent").asText());
    }

    @Test
    void deleteFile_whenApproved_deletesFile() throws Exception {
        var filePath = tempDir.resolve("to-delete.txt");
        Files.writeString(filePath, "some content");

        var fileChangeService = new FileChangeService();
        var chunks = new ArrayList<StreamChunk>();
        var tool = new FileEditTool(enabledShellAccess(), fileChangeService, chunks::add);

        runWithAutoApprove(fileChangeService, chunks, () -> tool.deleteFile(filePath.toString()));

        assertFalse(Files.exists(filePath), "File should be deleted after approval");
    }

    @Test
    void deleteFile_whenRejected_doesNotDeleteFile() throws Exception {
        var filePath = tempDir.resolve("keep.txt");
        Files.writeString(filePath, "keep me");

        var fileChangeService = new FileChangeService();
        var chunks = new ArrayList<StreamChunk>();
        var tool = new FileEditTool(enabledShellAccess(), fileChangeService, chunks::add);

        runWithAutoReject(fileChangeService, chunks, () -> tool.deleteFile(filePath.toString()));

        assertTrue(Files.exists(filePath), "File should still exist after rejection");
    }

    @Test
    void createFile_emitsPendingChunkWithCorrectFields() throws Exception {
        var fileChangeService = new FileChangeService();
        var capturedChunk = new AtomicReference<StreamChunk>();
        var filePath = tempDir.resolve("emit-test.txt").toString();

        var executor = Executors.newSingleThreadExecutor();
        var future = executor.submit(() -> {
            var tool = new FileEditTool(enabledShellAccess(), fileChangeService, chunk -> {
                capturedChunk.set(chunk);
                if (StreamChunk.TYPE_FILE_CHANGE_PENDING.equals(chunk.type())) {
                    approveFirstPending(fileChangeService, chunk.content());
                }
            });
            return tool.createFile(filePath, "content");
        });
        future.get(5, TimeUnit.SECONDS);

        var chunk = capturedChunk.get();
        assertNotNull(chunk);
        assertEquals(StreamChunk.TYPE_FILE_CHANGE_PENDING, chunk.type());
        var json = JSON.readTree(chunk.content());
        assertEquals("CREATE", json.get("operation").asText());
        assertEquals(filePath, json.get("path").asText());
        assertNull(json.get("oldContent").textValue());
        assertEquals("content", json.get("newContent").asText());
        assertNotNull(json.get("changeId").asText());
    }

    @Test
    void modifyFile_emitsPendingChunkWithOldAndNewContent() throws Exception {
        var fileChangeService = new FileChangeService();
        var capturedChunk = new AtomicReference<StreamChunk>();
        var filePath = tempDir.resolve("modify-emit.txt");
        Files.writeString(filePath, "old");

        var executor = Executors.newSingleThreadExecutor();
        var future = executor.submit(() -> {
            var tool = new FileEditTool(enabledShellAccess(), fileChangeService, chunk -> {
                capturedChunk.set(chunk);
                if (StreamChunk.TYPE_FILE_CHANGE_PENDING.equals(chunk.type())) {
                    approveFirstPending(fileChangeService, chunk.content());
                }
            });
            return tool.modifyFile(filePath.toString(), "new");
        });
        future.get(5, TimeUnit.SECONDS);

        var json = JSON.readTree(capturedChunk.get().content());
        assertEquals("MODIFY", json.get("operation").asText());
        assertEquals("old", json.get("oldContent").asText());
        assertEquals("new", json.get("newContent").asText());
    }

    // --- helpers ---

    private String runWithAutoApprove(FileChangeService service, ArrayList<StreamChunk> chunks,
                                      java.util.concurrent.Callable<String> action) throws Exception {
        var executor = Executors.newSingleThreadExecutor();
        var future = executor.submit(() -> {
            var capturingService = new FileChangeService();
            // We need to intercept chunk emissions to approve - use a capturing chunk consumer
            throw new UnsupportedOperationException("use overload with capturing chunk consumer");
        });
        // Use the capturing tool pattern directly
        return runCapturing(service, chunks, action, true);
    }

    private String runWithAutoReject(FileChangeService service, ArrayList<StreamChunk> chunks,
                                     java.util.concurrent.Callable<String> action) throws Exception {
        return runCapturing(service, chunks, action, false);
    }

    private String runCapturing(FileChangeService service, ArrayList<StreamChunk> chunks,
                                 java.util.concurrent.Callable<String> action, boolean approve) throws Exception {
        var executor = Executors.newSingleThreadExecutor();
        var resultFuture = executor.submit(() -> {
            // Wrap the action so we can intercept the chunk
            // The action already uses `chunks::add` consumer - but we need to intercept FILE_CHANGE_PENDING
            // So we call action directly (it was created with the service passed in) but we need to approve/reject
            // We watch service.hasPending() and approve/reject once pending
            while (!service.hasPending()) {
                Thread.sleep(1);
            }
            if (approve) {
                // We need the changeId - it's in the chunk. chunks is shared via the consumer.
                // Wait for chunk to appear
                while (chunks.isEmpty()) Thread.sleep(1);
                var pendingChunk = chunks.stream()
                        .filter(c -> StreamChunk.TYPE_FILE_CHANGE_PENDING.equals(c.type()))
                        .findFirst().orElse(null);
                if (pendingChunk != null) {
                    var changeId = JSON.readTree(pendingChunk.content()).get("changeId").asText();
                    service.approve(changeId);
                }
            } else {
                while (chunks.isEmpty()) Thread.sleep(1);
                var pendingChunk = chunks.stream()
                        .filter(c -> StreamChunk.TYPE_FILE_CHANGE_PENDING.equals(c.type()))
                        .findFirst().orElse(null);
                if (pendingChunk != null) {
                    var changeId = JSON.readTree(pendingChunk.content()).get("changeId").asText();
                    service.reject(changeId);
                }
            }
            return (String) null;
        });

        // Run action on main thread (blocks waiting for approval)
        var mainFuture = executor.submit(action);
        resultFuture.get(5, TimeUnit.SECONDS);
        return mainFuture.get(5, TimeUnit.SECONDS);
    }

    private void approveFirstPending(FileChangeService service, String chunkContent) {
        try {
            var changeId = JSON.readTree(chunkContent).get("changeId").asText();
            service.approve(changeId);
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }
}

