import java.util.concurrent.CompletableFuture;
import java.util.concurrent.ConcurrentHashMap;

@Service
public class FileChangeService {

    private final ConcurrentHashMap<String, CompletableFuture<Boolean>> pending = new ConcurrentHashMap<>();

    public CompletableFuture<Boolean> requestChange(String changeId) {
        var future = new CompletableFuture<Boolean>();
        pending.put(changeId, future);
        return future;
    }

    public void approve(String changeId) {
        var future = pending.remove(changeId);
        if (future != null) {
            future.complete(true);
        }
    }

    public void reject(String changeId) {
        var future = pending.remove(changeId);
        if (future != null) {
            future.complete(false);
        }
    }

    public boolean hasPending() {
        return !pending.isEmpty();
    }
}

