    private final FileChangeService fileChangeService;

    public FileChangeController(FileChangeService fileChangeService) {
        this.fileChangeService = fileChangeService;
    }

    @PostMapping("/{changeId}/approve")
    public ResponseEntity<Void> approve(@PathVariable String changeId) {
        fileChangeService.approve(changeId);
        return ResponseEntity.ok().build();
    }

    @PostMapping("/{changeId}/reject")
    public ResponseEntity<Void> reject(@PathVariable String changeId) {
        fileChangeService.reject(changeId);
        return ResponseEntity.ok().build();
    }
}

