import type { PendingFileChange } from '../types';

type DiffLine =
  | { type: 'added'; content: string }
  | { type: 'deleted'; content: string }
  | { type: 'unchanged'; content: string };

function computeLcsDiff(oldLines: string[], newLines: string[]): DiffLine[] {
  const m = oldLines.length;
  const n = newLines.length;

  // For very large files, fall back to showing full replacement
  if (m * n > 200_000) {
    return [
      ...oldLines.map((l) => ({ type: 'deleted' as const, content: l })),
      ...newLines.map((l) => ({ type: 'added' as const, content: l })),
    ];
  }

  const dp: number[][] = Array.from({ length: m + 1 }, () => new Array(n + 1).fill(0));
  for (let i = 1; i <= m; i++) {
    for (let j = 1; j <= n; j++) {
      dp[i][j] = oldLines[i - 1] === newLines[j - 1]
        ? dp[i - 1][j - 1] + 1
        : Math.max(dp[i - 1][j], dp[i][j - 1]);
    }
  }

  const result: DiffLine[] = [];
  let i = m, j = n;
  while (i > 0 || j > 0) {
    if (i > 0 && j > 0 && oldLines[i - 1] === newLines[j - 1]) {
      result.unshift({ type: 'unchanged', content: oldLines[i - 1] });
      i--;
      j--;
    } else if (j > 0 && (i === 0 || dp[i][j - 1] >= dp[i - 1][j])) {
      result.unshift({ type: 'added', content: newLines[j - 1] });
      j--;
    } else {
      result.unshift({ type: 'deleted', content: oldLines[i - 1] });
      i--;
    }
  }
  return result;
}

function computeDiff(change: PendingFileChange): DiffLine[] {
  if (change.operation === 'CREATE') {
    return (change.newContent ?? '').split('\n').map((l) => ({ type: 'added', content: l }));
  }
  if (change.operation === 'DELETE') {
    return (change.oldContent ?? '').split('\n').map((l) => ({ type: 'deleted', content: l }));
  }
  // MODIFY
  const oldLines = (change.oldContent ?? '').split('\n');
  const newLines = (change.newContent ?? '').split('\n');
  return computeLcsDiff(oldLines, newLines);
}

function operationLabel(op: PendingFileChange['operation']): string {
  if (op === 'CREATE') return 'Create';
  if (op === 'DELETE') return 'Delete';
  return 'Modify';
}

function operationColor(op: PendingFileChange['operation']): string {
  if (op === 'CREATE') return 'text-green-400';
  if (op === 'DELETE') return 'text-red-400';
  return 'text-yellow-400';
}

export default function FileDiffCard({
  change,
  onApprove,
  onReject,
}: {
  change: PendingFileChange;
  onApprove: () => void;
  onReject: () => void;
}) {
  const [expanded, setExpanded] = useState(true);
  const diff = computeDiff(change);
  const addedCount = diff.filter((l) => l.type === 'added').length;
  const deletedCount = diff.filter((l) => l.type === 'deleted').length;

  return (
    <div className="self-stretch mx-0 py-3 px-4 rounded-lg border border-accent/50 bg-accent/10 text-sm">
      <div className="flex items-center gap-2 mb-2">
        <span className="text-[0.6875rem] font-semibold uppercase tracking-wide text-accent">
          File change approval required
        </span>
        <span className={`ml-1 text-[0.6875rem] font-semibold uppercase ${operationColor(change.operation)}`}>
          {operationLabel(change.operation)}
        </span>
      </div>

      <div className="mb-2 flex items-center gap-2 min-w-0">
        <span className="font-mono text-xs text-text-bright bg-bg-input px-2 py-0.5 rounded border border-border truncate max-w-full">
          {change.path}
        </span>
        {(addedCount > 0 || deletedCount > 0) && (
          <span className="text-[0.6875rem] shrink-0">
            {addedCount > 0 && <span className="text-green-400">+{addedCount}</span>}
            {addedCount > 0 && deletedCount > 0 && <span className="text-text-dim mx-0.5">/</span>}
            {deletedCount > 0 && <span className="text-red-400">-{deletedCount}</span>}
          </span>
        )}
      </div>

      <div className="mb-3">
        <button
          className="text-[0.6875rem] text-text-dim hover:text-text-bright transition-colors duration-100 flex items-center gap-1"
          onClick={() => setExpanded((v) => !v)}
        >
          {expanded ? '▾' : '▸'} Diff
        </button>
        {expanded && (
          <div className="mt-1.5 rounded-lg border border-border overflow-hidden max-h-[400px] overflow-y-auto">
            {diff.length === 0 ? (
              <div className="p-2 text-xs text-text-dim font-mono">(no changes)</div>
            ) : (
              <table className="w-full border-collapse text-xs font-mono">
                <tbody>
                  {diff.map((line, idx) => (
                    <tr
                      key={idx}
                      className={
                        line.type === 'added'
                          ? 'bg-green-950/60'
                          : line.type === 'deleted'
                            ? 'bg-red-950/60'
                            : ''
                      }
                    >
                      <td className="w-6 text-center select-none text-[0.65rem] px-1 py-0 border-r border-border text-text-dim">
                        {line.type === 'added' ? '+' : line.type === 'deleted' ? '−' : ' '}
                      </td>
                      <td
                        className={`px-2 py-0 whitespace-pre break-all leading-5 ${
                          line.type === 'added'
                            ? 'text-green-300'
                            : line.type === 'deleted'
                              ? 'text-red-300'
                              : 'text-text-dim'
                        }`}
                      >
                        {line.content}
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            )}
          </div>
        )}
      </div>

      <div className="flex gap-2">
        <button
          className="py-1.5 px-4 bg-accent text-white rounded-lg text-xs font-medium cursor-pointer transition-colors duration-150 hover:bg-accent-hover"
          onClick={onApprove}
        >
          Approve
        </button>
        <button
          className="py-1.5 px-4 bg-bg-input text-danger border border-danger/50 rounded-lg text-xs font-medium cursor-pointer transition-colors duration-150 hover:bg-danger/10"
          onClick={onReject}
        >
          Reject
        </button>
      </div>
    </div>
  );
}

