                      {part.content}
                    </pre>
                  </details>
                ) : part.type === 'reasoning' ? (
                  <details key={i} className="mb-2" open>
                    <summary className="cursor-pointer text-text-dim text-xs font-semibold uppercase">
                      Thinking
                    </summary>
