    32→    @Tool(description = "Create a new file with the specified content. Shows a diff preview to the user before writing. Only works when shell access is enabled.")
    33→    public String createFile(
    34→            @ToolParam(description = "Absolute path of the file to create") String path,
    35→            @ToolParam(description = "Content of the file") String content) {
    36→        if (!shellAccessService.isEnabled()) {
