    49→    @Tool(description = "Modify an existing file by replacing its entire content. Shows a diff preview to the user before writing. Only works when shell access is enabled.")
    50→    public String modifyFile(
    51→            @ToolParam(description = "Absolute path of the file to modify") String path,
