    63→    @Tool(description = "Delete an existing file. Shows the current file content to the user before deleting. Only works when shell access is enabled.")
    64→    public String deleteFile(
    65→            @ToolParam(description = "Absolute path of the file to delete") String path) {
    66→        if (!shellAccessService.isEnabled()) {
