@Tool(description = "Edit specific sections of an existing file by providing a list of oldText/newText pairs. Each pair replaces the first occurrence of oldText with newText. Shows a diff preview to the user before writing. Only works when shell access is enabled.")
public String editFile(
        @ToolParam(description = "Absolute path of the file to edit") String path,
        @ToolParam(description = "List of text replacements to apply in order") List<FileEdit> edits) {
    if (!shellAccessService.isEnabled()) {
        return "Error: Shell access is currently disabled.";
    }
    var oldContent = readFileOrEmpty(path);
    var patched = applyEdits(oldContent, edits);
    if (patched == null) {
        return "Error: one or more oldText values were not found in the file.";
    }
    var newContent = patched;
    return proposeAndExecute("editFile", "MODIFY", path, oldContent, newContent, () -> {
        Files.writeString(Path.of(path), newContent);
        return "File edited: " + path;
    });
}

private static String applyEdits(String content, List<FileEdit> edits) {
    var result = content;
    for (var edit : edits) {
        if (!result.contains(edit.oldText())) {
            return null;
        }
        result = result.replace(edit.oldText(), edit.newText());
    }
    return result;
}

